/**
 * Tests for the HTML-LB (full) equal-coverage benchmark claim.
 *
 * Core assertion: when the same neurons are returned in both HTML and Markdown
 * formats and all HTML tags are stripped, the resulting plain-text sizes
 * are comparable (within ±30%).
 *
 * This validates the key insight documented in docs/BENCHMARKS.md (v5):
 *   HTML-LB(full) = 811t avg, recall 87%
 *   Markdown      = 823t avg, recall 87%
 *   => Equal coverage, approximately equal tokens (1.5% difference)
 *
 * The test uses the bench/html-generic and bench/markdown fixture files
 * (generated by bench-html-to-md.mjs and bench-strip-html.mjs) which are
 * 1:1 conversions of the same canonical LazyBrain neurons.
 */

import { describe, it, expect } from 'vitest';
import { readdir, readFile } from 'node:fs/promises';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');
const BENCH_HTML = join(ROOT, 'bench', 'html-generic');
const BENCH_MD = join(ROOT, 'bench', 'markdown');

// ---------------------------------------------------------------------------
// Plain-text extraction (mirrors extractPlainText in run-benchmark.mjs)
// ---------------------------------------------------------------------------

function extractPlainText(html: string): string {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&gt;/g, '>')
    .replace(/&lt;/g, '<')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/[\t\f\v]+/g, ' ')
    .replace(/ {2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// ---------------------------------------------------------------------------
// Load bench fixture pairs
// ---------------------------------------------------------------------------

async function loadBenchPairs(): Promise<Array<{ name: string; htmlText: string; mdText: string }>> {
  let htmlFiles: string[];
  let mdFiles: string[];

  try {
    htmlFiles = (await readdir(BENCH_HTML)).filter((f) => f.endsWith('.html'));
    mdFiles = (await readdir(BENCH_MD)).filter((f) => f.endsWith('.md') && f !== 'README.md');
  } catch {
    // Bench fixtures not generated — skip tests gracefully
    return [];
  }

  const mdSet = new Set(mdFiles.map((f) => f.replace('.md', '')));
  const pairs: Array<{ name: string; htmlText: string; mdText: string }> = [];

  for (const htmlFile of htmlFiles) {
    const baseName = htmlFile.replace('.html', '');
    if (!mdSet.has(baseName)) continue;
    try {
      const htmlRaw = await readFile(join(BENCH_HTML, htmlFile), 'utf8');
      const mdRaw = await readFile(join(BENCH_MD, baseName + '.md'), 'utf8');
      pairs.push({ name: baseName, htmlText: extractPlainText(htmlRaw), mdText: mdRaw });
    } catch {
      // skip unreadable pairs
    }
  }
  return pairs;
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('benchmark equal-coverage: HTML stripped vs Markdown', () => {
  it('bench fixtures exist and have matching HTML/MD pairs', async () => {
    const pairs = await loadBenchPairs();
    // If bench fixtures are not generated, skip gracefully
    if (pairs.length === 0) {
      console.warn(
        'Bench fixtures not found — run bench-html-to-md.mjs and bench-strip-html.mjs first.',
      );
      return;
    }
    expect(pairs.length).toBeGreaterThan(10);
  });

  it('HTML stripped text is within 30% of Markdown character count per neuron (equal-coverage claim)', async () => {
    const pairs = await loadBenchPairs();
    if (pairs.length === 0) return; // fixtures not generated — skip

    const outliers: string[] = [];
    for (const { name, htmlText, mdText } of pairs) {
      if (mdText.length === 0) continue;
      const ratio = htmlText.length / mdText.length;
      // HTML stripped should be within 0.7–1.3x of Markdown character count.
      // The benchmark measures avg 1.06x (6% larger), so 30% is a generous bound.
      if (ratio < 0.7 || ratio > 1.3) {
        outliers.push(`${name}: HTML=${htmlText.length} MD=${mdText.length} ratio=${ratio.toFixed(2)}`);
      }
    }
    expect(outliers).toHaveLength(0);
  });

  it('aggregate token ratio across all bench pairs is between 0.8 and 1.25', async () => {
    const pairs = await loadBenchPairs();
    if (pairs.length === 0) return; // fixtures not generated — skip

    const totalHtmlChars = pairs.reduce((s, p) => s + p.htmlText.length, 0);
    const totalMdChars = pairs.reduce((s, p) => s + p.mdText.length, 0);
    const avgRatio = totalHtmlChars / totalMdChars;

    // The measured ratio on the LB_rebuild brain is ~1.06.
    // Assert it stays in a reasonable range to catch regressions.
    expect(avgRatio).toBeGreaterThan(0.8);
    expect(avgRatio).toBeLessThan(1.25);
  });

  it('HTML stripped text for a Q1 oracle neuron contains expected gold phrases', async () => {
    const pairs = await loadBenchPairs();
    if (pairs.length === 0) return; // fixtures not generated — skip

    const root = pairs.find((p) => p.name.includes('acme-root'));
    if (!root) return; // oracle not in bench sample — skip

    // Gold phrases from Q1 oracle neurons (same as benchmark QUERIES[0].goldPhrases)
    const goldPhrases = ['acme-app', 'AdminPanel', 'content-pipeline'];
    const found = goldPhrases.filter((phrase) =>
      root.htmlText.toLowerCase().includes(phrase.toLowerCase()),
    );
    // At least one gold phrase must survive HTML stripping
    expect(found.length).toBeGreaterThan(0);
  });

  it('HTML stripped text preserves content equivalently to Markdown (gold phrase recall parity)', async () => {
    const pairs = await loadBenchPairs();
    if (pairs.length === 0) return; // fixtures not generated — skip

    // Q2 gold phrases — present in auth-bug oracle neurons
    const goldPhrases = [
      'auth, bug, frontend',
      'auth, bug, performance',
      'auth, database, testing',
    ];

    for (const phrase of goldPhrases) {
      const htmlHit = pairs.some((p) => p.htmlText.toLowerCase().includes(phrase.toLowerCase()));
      const mdHit = pairs.some((p) => p.mdText.toLowerCase().includes(phrase.toLowerCase()));

      if (mdHit) {
        // If Markdown has the gold phrase, HTML stripped must also have it
        // (stripping markup cannot remove prose content)
        expect(htmlHit).toBe(true);
      }
    }
  });
});
